import json
import boto3

QUEUE_URL = 'https://sqs.us-east-1.amazonaws.com/123456789012/your-queue'
REGION_NAME = 'us-east-1'

def process_message(message):
    # Parse message body and execute actions based on message content
    # This is a placeholder for dynamic message processing
    print('Processing message:', json.loads(message['Body']))

def main():
    sqs = boto3.client(service_name='sqs', region_name=REGION_NAME)

    while True:
        response = sqs.receive_message(QueueUrl=QUEUE_URL, WaitTimeSeconds=20)

        if 'Messages' in response:
            for message in response['Messages']:
                process_message(message)
                sqs.delete_message(QueueUrl=QUEUE_URL, ReceiptHandle=message['ReceiptHandle'])
        else:
            print('No messages received')

if __name__ == "__main__":
    main()